import java.io.*;
import java.nio.charset.StandardCharsets;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        // Read entire input as a string
        String data = new String(System.in.readAllBytes(), StandardCharsets.UTF_8);
        // Convert escaped "\n" sequences to real newlines to handle both formats
        data = data.replace("\\n", "\n");
        Scanner sc = new Scanner(data);
        StringBuilder out = new StringBuilder();
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            HashMap<Long, Integer> freq = new HashMap<>();
            int maxFreq = 0;
            for (int i = 0; i < N; i++) {
                long val = sc.nextLong();
                int cnt = freq.getOrDefault(val, 0) + 1;
                freq.put(val, cnt);
                if (cnt > maxFreq) maxFreq = cnt;
            }
            int keep;
            if (N == 1) {
                keep = 1;
            } else {
                keep = Math.max(maxFreq, 2);
            }
            out.append(N - keep).append('\n');
        }
        System.out.print(out.toString());
    }
}

